function Save_setItem(name, value) {
  if (!isPrivate) localStorage.setItem(name, value);
}
function Save_getItem(name, pardefaut) {
  if (!isPrivate) return localStorage.getItem(name);
  else return pardefaut;
}
function save_lire(str1) {
  sauvegarde_trapmouse = [];
  var str = str1.split(",");
  var ligne = 0;
  var taille;
  var ii = 0;
  while (ii < str.length) {
    sauvegarde_trapmouse[ii] = { numetoile: 0 };
    sauvegarde_trapmouse[ii].numetoile = +str[ii++];
  }
}
function save_ecrit() {
  var str = "";
  for (var i = 0; i < nombre_levels; i++) {
    str += "" + sauvegarde_trapmouse[i].numetoile;
    if (i < nombre_levels - 1) str += ",";
  }
  Save_setItem("trapmouse_sauvegarde", str);
}
