trapmouse.Boot.prototype = {
  preload: function () {
    this.game.load.image(
      "preloadSprite",
      "assets/load_bar" + resolution + ".png"
    );
    this.game.load.image(
      "preloadSprite01",
      "assets/loaded_bar" + resolution + ".png"
    );
    this.game.load.image(
      "bgZibbo",
      "assets/zibbo_preload" + resolution + ".png"
    );
    this.game.load.image("loading", "assets/loading" + resolution + ".png");
    game.load.image("rotate", "assets/rotate" + resolution + ".png");
    game.load.atlasXML("sprites", "assets/sprites.png", "assets/sprites.xml");
  },
  create: function () {
    this.input.maxPointers = 1;
    if (this.game.device.desktop) {
      this.scale.scaleMode = Phaser.ScaleManager.SHOW_ALL;
      this.scale.pageAlignHorizontally = true;
      this.scale.pageAlignVertically = true;
    } else {
      this.scale.scaleMode = Phaser.ScaleManager.EXACT_FIT;
      this.scale.forceOrientation(false, true, "rotate");
    }
    this.game.scale.enterPortrait.add(this.rescale, this);
    this.game.scale.enterLandscape.add(this.rescale, this);
    this.scale.setScreenSize(true);
    var SpilData = { id: "576742227280294232" };
    GameAPI.loadAPI(function (apiInstance) {
      if (window.console && window.console.log) {
        console.log("GameAPI version " + apiInstance.version + " loaded!");
      }
      apiInstance.Branding.displaySplashScreen(continueGame);
      trapmouse.logoData = apiInstance.Branding.getLogo();
      if (trapmouse.logoData.image) {
      }
      this.game.state.start("preload");
    }, SpilData);
  },
  rescale: function () {
    var _game = this.game;
    setTimeout(function () {
      _game.scale.refresh();
      setTimeout(function () {
        _game.scale.refresh();
      }, 400);
    }, 400);
  },
};
