  TestPrivate: function () {
    var testKey = "qeTest",
      storage = window.sessionStorage;
    try {
      storage.setItem(testKey, "1");
      storage.removeItem(testKey);
    } catch (error) {
      if (
        error.code === DOMException.QUOTA_EXCEEDED_ERR &&
        storage.length === 0
      ) {
        isPrivate = true;
      } else {
        isPrivate = false;
      }
    }
  },
